// ── Wire helpers ──────────────────────────────────────────────────────────────

func appendPackedFixed64(b []byte, fieldNum protowire.Number, vals []float64) []byte {
	packed := make([]byte, 0, len(vals)*8)
	for _, v := range vals {
		packed = protowire.AppendFixed64(packed, math.Float64bits(v))
	}
	b = protowire.AppendTag(b, fieldNum, protowire.BytesType)
	return protowire.AppendBytes(b, packed)
}

func unpackFixed64(b []byte) []float64 {
	out := make([]float64, 0, len(b)/8)
	for len(b) >= 8 {
		v, _ := protowire.ConsumeFixed64(b)
		out = append(out, math.Float64frombits(v))
		b = b[8:]
	}
	return out
}

func unmarshalStringPair(b []byte) (k, v string) {
	for len(b) > 0 {
		num, typ, n := protowire.ConsumeTag(b)
		if n < 0 { return }
		b = b[n:]
		if typ == protowire.BytesType {
			s, n := protowire.ConsumeString(b)
			if n < 0 { return }
			if num == 1 { k = s } else if num == 2 { v = s }
			b = b[n:]
		} else {
			n := protowire.ConsumeFieldValue(num, typ, b)
			if n < 0 { return }
			b = b[n:]
		}
	}
	return
}
